import {
    SLIDER_VIEW_CLASSNAME,
    TRACK_FLASH_CLASSNAME,
    TRACK_SYMBOL_CLASSNAME,
    HIGHLIGHT_LEGEND_CLASSNAME,
    SLIDER_HANDLE_TRACK_CLASSNAME
} from '../../../legend/legend-constants';
import { Registry } from '../../../core/zc-registry';
import { validateNullVal, defined } from '../../../utils/zcutils';
import { createElement } from '../../../utils/zcsvgutils';
import { HighlightTooltip } from '../visual-effects/highlight-tooltip';
// import { legend_helpers } from '../../legend-helper';
import { legend_helpers } from '../../../core/main-zc-init';
import { getHoverOptions } from '../legend-event-helpers';

/**
 *
 * @param chart
 * @return {Legend Event options}
 */
export function _legendSizeSliderEventArguments(chart, id) {
    let legendInstance = chart.legends.get(id),
        //
        { component, meta, element, highlightManager } = legendInstance,
        { scaleComponent } = meta,
        { dataType } = scaleComponent.schema.data,
        //
        { brushOptions } = component,
        { config } = brushOptions,
        { events: eventsConfig } = config,
        hoverOptions = getHoverOptions(config),
        container = element.selectAll(`g.${SLIDER_VIEW_CLASSNAME}`),
        trackerElement = getTrackerElement(element, config),
        highlightElement = getHighlightElement(container),
        tooltip = getTooltip(chart, highlightElement, legendInstance.meta.config),
        //
        eventDisabled = eventsConfig && validateNullVal(eventsConfig.enabled, true) == false,
        enabled = legendInstance.enabled && !eventDisabled && defined(hoverOptions.type);

    return { enabled, trackerElement, highlightElement, highlightManager, tooltip, ...brushOptions, dataType, legendInstance };
}

/**
 * Returns tracker element
 * @param  {D3Selectiion} container
 * @return {D3Selectiion}
 */
function getTrackerElement(container, config) {
    let selector = config.filter.enabled
        ? `.selection,.${SLIDER_HANDLE_TRACK_CLASSNAME}`
        : `.${TRACK_FLASH_CLASSNAME},.${TRACK_SYMBOL_CLASSNAME}`;

    return container.selectAll(selector).style('pointer-events', 'all');
}

/**
 * Returns highlight element
 * @param  {D3Selectiion} container
 * @return {D3Selectiion}
 */
function getHighlightElement(container) {
    return createElement('g', `.${HIGHLIGHT_LEGEND_CLASSNAME}`, [1], container)
        .style('pointer-events', 'none')
        .style('display', null)
        .style('opacity', 1);
}

function getTooltip(chart, element, config) {
    let hoverOptions = getHoverOptions(config),
        tooltipOptions = {
            config: hoverOptions.tooltip,
            orient: legend_helpers.getOrient(config),
            element,
            chart
        };

    return HighlightTooltip(tooltipOptions);
}

Registry.setComponent('_legendSizeSliderEventArguments', _legendSizeSliderEventArguments);
